local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxMonthCardCtrl:LxBaseCtrl
local LxMonthCardCtrl = classX("LxMonthCardCtrl", LxBaseCtrl)

function LxMonthCardCtrl:GetMonthCardRed()
    for i, v in pairs(GameTable.MonthlyCardRef) do
        if(self:GetMonCardRedById(v.refId))then
            return true
        end
    end
    return false
end
function LxMonthCardCtrl:GetMonCardRedById(refId)
    if(refId == 3)then
        return false
    end
    ---@type LxMonthCardObj
    local cardObj = ModuleCenter.MonthCard:GetCardObj(refId)
    if(cardObj == nil)then
        return false
    end
    if(cardObj.day <= 0 and cardObj.week <= 0)then
        return false
    end
    return true
end
return LxMonthCardCtrl
